#include <bits/stdc++.h>
using namespace std;

void generatePermutations(string& s, string& curr, map<char, int>& freq, 
                         vector<string>& result) {
    if(curr.length() == s.length()) {
        result.push_back(curr);
        return;
    }

    for(auto& pair : freq) {
        if(pair.second > 0) {
            curr.push_back(pair.first);
            pair.second--;

            generatePermutations(s, curr, freq, result);

            curr.pop_back();
            pair.second++;
        }
    }
}

vector<string> findPermutations(string s) {
    vector<string> result;
    map<char, int> freq;  // Using map for sorted order

    // Count frequency of each character
    for(char c : s) {
        freq[c]++;
    }

    string curr = "";
    generatePermutations(s, curr, freq, result);

    return result;
}

int main() {
    string s;
    cin >> s;

    vector<string> perms = findPermutations(s);

    for(const string& perm : perms) {
        cout << perm << " ";
    }
    cout << endl;

    return 0;
}
